%%
%[text] ## SNTHERM
%[text] See the latex doc for detailed description, copy here eventually. 
%%
syms T L_v R_v T_f a b c
% syms rho_v e_s 
T_d = T - T_f;
e_s = a * exp(b * T_d / (c + T_d)) %[output:5e8fdf4d]
rho_v = e_s / (R_v * T) %[output:4cbfbaa0]
diff(rho_v, T) %[output:8550aa20]
diff(e_s, T) %[output:419afdfe]
%[text] Thus $\\frac{de\_s}{dT}$ can be written:
%[text] $\\frac{de\_s}{dT} = e\_s \\left( \\frac{b}{c + T\_d} - \\frac{b T\_d}{ \[c + T\_d\]^2} \\right)$
%%
%[text] A common form for $e\_s$ is:
%[text] $e\_s = e\_{s0} \\exp\\left\[\\frac{L\_v}{R\_v}\\left(\\frac{1}{T\_f} - \\frac{1}{T}\\right)\\right\]$
e_s = a * exp(L_v / R_v * (1/T_f - 1/T)) %[output:51d3112b]
diff(e_s, T) %[output:70ad70c1]
%%
%[text] ## GETKVAPOR
%[text] This is the original implementation in GETKVAPOR which follows Liston's definition:
%[text] $k\_v = \\frac{D\_e L\_s}{R\_v T} \\frac{de\_s}{dT}$
%[text] Define coefficients over ice
A = 611.15;             % reference vapor pressure [Pa]
B = 22.452;             % unitless coefficient
C = 272.55;             % unitless coefficient
%[text] Define the 'temperature exponent', Anderson (1976) eq. 3.13
nd = 14;
%[text] Compute the temperature depression
Tdep = T - Tf;
%[text] Compute the saturation vapor pressure in the ice and its derivative with respect to temperature
esi = A * exp((B * Tdep) ./ (C + Tdep));    % [Pa]
desi_dT = B * C * esi ./ ((C + Tdep) .^ 2);   % [Pa K-1]
%[text] Compute the diffusivity
De = 9e-5 * (T / Tf) .^ nd;                     % [m2 s-1]
%[text] Compute the diffusion coefficient in units that thermal conductivity carries
%[text] NOTE: This is Liston's version, subsequently I've updated GETKVAPOR to use the correct derivative:
k_vap = Ls * De ./ (Rv .* T) .* desi_dT;        % [W m-1 K-1]
%%
%[text] ## SNTHRM version:
%[text] This is the version originally at the bottom of GETKVAPOR
% snthrm version, governing equation:
% d_rov_dT = c1k / T^2 * (Lvk / (Rv * T) - 1) * exp(-(Lvk / (Rv * T)))
%
% Simplify that by defining:
% Tk = (Lvk / (Rv * T))
%
% Then we have:
%
% d_rov_dT = c1k / T^2 * (Tk - 1) * exp(-Tk)
%
% where k = ice if f_liq <= f_liq_phase_switch_threshold and k = liq otherwise
% c1_ice and c1_liq are combined constants which can be computed a priori
% T_ice and T_liq have to be computed on the fly once f_liq is known

% Define the constants
Lv = 2.500e6;
c1_ice = 8.047e9;                                  % [kg/m3 K]
c1_liq = 5.726e8;                                  % [kg/m3 K]

% Locate nodes in the liquid branch
iliq = T >= TL;

% Compute the exponent Tk
Tice = Ls ./ (Rv * T);                             % [-]
Tliq = Lv ./ (Rv * T(iliq));                       % [-]

% Compute d_ro_vap_dT with respect to ice
CkT = c1_ice / T .^2 .* (Tice - 1) .* exp(-Tice);

% Adjust d_ro_vap_dT with respect to liq
CkT(iliq) = c1_liq / T(iliq) .^ 2 .* (Tliq - 1) .* exp(-Tliq);

% Compute vapor diffusion thermal conductivity
k_vap = Ls * De .* CkT;
%[text] I also had this at the top of VAPOR, which computed sat vapor pressure, but I combined into VAPPRESS:
%VAPOR compute the saturation vapor pressure at the surface
%
% capital P in Jordan
% Pv0_sat = es0 = saturation water vapor pressure at T = 0oC, P = 6.1360 mb
% Pvk_sat = es = saturation water vapor pressure wrt phase k
% note: Pvk_sat = esi for ice i.e., within the ice matrix, here
%%
%[text] Reconcile them
%[text] Nov 2023: The d\_ro\_vap\_dT expressions are correct, following Jordan, but subsequent steps use Liston's definition and the substitute the expression between ro\_vap and e\_s and that ends up giving the wrong answer
%[text] Compute the equilibrium saturation water vapor density wrt phase k: \[kg m-3\] (ro\_vk\_sat)
ro_vap = esi ./ (Rv * T);
%[text] Compute bulk vapor density (Eq. 18) (assume f\_rh = 1.0) \[kg m-3\]
bd_vap = (1.0 - f_liq - f_ice) .* ro_vap;
%[text] Derivative of saturated vapor density wrt to temperature over ice (Eq. 20)
d_ro_vap_dT = ro_vap .* (B * C ./ (C + Tdep) .^ 2 - 1 ./ T);
%[text] Compute the heat (enthalpy) per unit volume: \[J m-3\]
H_vap = Ls * bd_vap;
%[text] Now, note that d\_ro\_vap\_sat\_dT can be written:
d_ro_vap_dT = ro_vap .* B * C ./ (C + Tdep) .^ 2 - ro_vap ./ T;
%[text] And the vapor heat diffusion coefficient can be computed from vapor pressure like this:
%[text] NOTE: This is Liston's k\_vap:
desi_dT = esi .* B .* C ./ (C + Tdep) .^ 2;  % [Pa K-1]
De = 9e-5 .* (T / Tf) .^ 14;                 % [m2 s-1]
k_vap = Ls * De ./ (Rv * T) .* desi_dT;      % [W m-1 K-1]
%[text] Substitute desi\_dT into k\_vap:
k_vap = Ls * De ./ (Rv * T) .* esi .* B .*C ./ (C + Tdep) .^ 2; % [W m-1 K-1]
%[text] But we know that ro\_vap\_sat = esi ./ (Rv .\* T)
%[text] Note: This is Liston's k\_vap:
k_vap = ro_vap .* Ls .* De .* B .* C ./ (C + Tdep) .^ 2; % [W m-1 K-1]
%[text] Also, we can rearrange d\_ro\_vap\_sat\_dT for ro\_vap\_sat.\*B\*C./(C+Td).^2
% ro_vap_sat .* B * C ./ (C+Td).^2 = d_ro_vap_sat_dT + ro_vap_sat./T

% then plug that in to k_vap expression:

% UPDATE Nov 2023: THIS IS THE SOURCE OF THE CONFUSION!! I tried to reconcile
% Jordan and Liston without understanding the fundamental issue was their
% different definitions of k_vap, Jordan being based on d_ro_vap_dT and Liston
% on d_es_dT, so this final step is wrong!!
k_vap = Ls * De .* (d_ro_vap_dT + ro_vap ./ T) % [W m-1 K-1]

%%
%[text] ## Yen's diffusivity enhancement
%[text] Increase the vapor diffusivity to account for ventilation in the very low-density near-surface ice following Yen et al. 1981.
Dep = 10; % 6.74
k_vap = Dep * Ls .* De ./ (Rv * T) .* desi_dT;    % [W m-1 K-1]

% equivalent to this:
%   G = 40e-3;
%   De = De .* 33.511 .* sqrt(G + 4.56e-4);
%[text] Test the density-dependent equation
G = 40e-3;
De = 9e-5 * (T / Tfp) .^ nd;
ro_s = ro_snow_dry / 1000;
idx = ro_s < 0.9;
De(idx) = De(idx) + 0.0513 * (ro_s(idx)) .^ 3.2 .* G ^ 0.615;

k_vap = Ls * De ./ (Rv * T) .* desi_dT; % [W m-1 K-1]
%[text] Yosida, 1950 found De = 0.7 to 1.0e-4 m2/s, about 4-5x larger than D0, where D0 is water vapor diffusivity in air. Forced convection near the surface increases De substantially for unconsolidated snow, which is analogous to weathering crust, which is totally unconsolidated.
%%
%[text] ## SNTHRM
% note: in Jordan, Pvk_sat is defined, but not used. In icemodel, this is
% es0 for the surface, and esi within the ice matrix over ice, and would be
% esl over liquid but I just call it esi. Similarly, Jordan defines and
% uses ro_vk_sat (ro_vap_sat wrt to constituent k), but I don't use it
% except here. It's easy to confuse ro_vk_sat and Pvk_sat in Jordan b/c the
% rho and P are similar.

% Jordan notation:

% gamma_v   - bulk vapor density = mass vapor / total volume (kg/m3)
% gamma_v   - theta_v * ro_v = theta_v * frh * ro_vk_sat
% ro_vk_sat - equilibrium water vapor density wrt phase k (kg/m3)
% theta_v   - fractional volume (m3/m3) (frac_ice/frac_air/frac_liq)

% Pvk_sat       = es0 / esi         (could call this Pvap_sat)
% ro_vap_sat    = ro_vap_sat        (previously undefined in Glen's model)
% ro_vap_sat    = Pvk_sat/(Rv*T)    (conversion b/w esi and ro_vap_sat)
% CkT           = d_ro_vap_sat_dT   (previously undefined in Glen's model)
% desi_dT       = dPvk_sat_dT       (undefined in Jordan)
%                                   (could call this dPvap_sat_dT)
% 
% Uvap          = -Deos * (T / Tf) ^ n * CkT * dT / dz
%               = -Deos * (T / Tf) ^ n * dbvdT * dT / dz
% 
% From GETGAMMA:
% kvap          = De0 * (T / Tfp) ^ n * Ls / (Rv * T) * desi/dT

% es0 = VAPOR = sat. water vapor pressure at the surface (wrt ice or water)
% ea  = VAPPRESS = same as above, but for the atmosphere above the surface
% esi = same as above, but over ice/water within the ice matrix, used in GETGAMMA

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

% In Jordan, it would be:
c1_ice      =   8.047e9;                                    % [kg/m3 K]
c1_liq      =   5.726e8;                                    % [kg/m3 K]
Ti          =   Ls / (Rv * T);                              % [-]
Tl          =   Lv / (Rv * T);                              % [-]

% over ice: (Eq. 20)
e           =   c1_ice / (T .^ 2) .* (Ti - 1) .* exp(-Ti);  % [kg/m3/K]

% over water:
e(i_liq)    =   c1_liq / (T .^2 ) .* (Tl - 1) .* exp(-Tl);  % [kg/m3/K]
d_ro_vap_dT =   e;                                          % [kg/m3/K]
H_vap       =   Ls * frac_air .* d_ro_vap_dT;               % [J/K/m3]

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

% Jordan calls d_ro_vap_dT 'CkT', where k refers to constituent ice, liq,
% Eq. 21: (I commented this out, I think drovap/dT is all I need)
dT          =   T(2:JJ) - T(1:JJ-1);
dT(JJ)      =   0.0;
Uvapor      =   -De * d_ro_vap_dT .* dT / dz;

% Jordan defines De0 in the front matter:
De0 = 9.2e-5; 

% PICK UP on equation 21, the remaining expressions for mass fluxes, involving
% melt/evap I think, and the condition that frac_liq be below a threshold for
% vapor diffusion to occur (no diffusion if saturated)

% A few notes though while this is fresh ... The quantity Uvapor is the
% diffusive vapor flux term in Eq. 17. I also have all the ingredients for
% the expulsion vapor flux, see equation 25:

%    Evapor = (porosity_sd - f_liq) .* f_rh .* d_ro_vap_dT;

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% these notes were further up

% below I have a different expression for Uvap but I think this is correct:
